#include <iostream>

class Calculator {
public:
    int add(int firstNum, int secondNum) {
        int sumOfTwo = firstNum + secondNum;
        return sumOfTwo;
    }
    double add(double val1, double val2) {
        return val1 + val2;
    }
    int add(int valA, int valB, int valC) {
        int tempSum = add(valA, valB);
        return add(tempSum, valC);
    }
};

int main() {
    Calculator calculatorInstance;
    std::cout << calculatorInstance.add(5, 3) << std::endl;
    std::cout << calculatorInstance.add(-10, 7) << std::endl;
    std::cout << calculatorInstance.add(0, 0) << std::endl;
    std::cout << calculatorInstance.add(5.5, 3.2) << std::endl;
    std::cout << calculatorInstance.add(-10.1, 7.5) << std::endl;
    std::cout << calculatorInstance.add(0.0, 0.0) << std::endl;
    std::cout << calculatorInstance.add(1, 2, 3) << std::endl;
    std::cout << calculatorInstance.add(-1, -2, -3) << std::endl;
    std::cout << calculatorInstance.add(10, -5, 2) << std::endl;
    return 0;
}
